+package org.apache.streampipes.commons.utils;
+
+import org.apache.streampipes.commons.exceptions.SpRuntimeException;
+
+import java.net.InetAddress;
+import java.net.URL;
+import java.util.Arrays;
+import java.util.HashSet;
+import java.util.Set;
+
+public class UrlValidator {
+
+  private static final Set<String> ALLOWED_SCHEMES = new HashSet<>(Arrays.asList("http", "https"));
+  private static final Set<String> ALLOWED_HOSTS = new HashSet<>(Arrays.asList(
+      "github.com",
+      "raw.githubusercontent.com",
+      "maven.apache.org",
+      "repo1.maven.org"
+  ));
+
+  public static void validateUrl(String urlString) throws SpRuntimeException {
+    if (urlString == null || urlString.trim().isEmpty()) {
+      throw new SpRuntimeException("URL cannot be null or empty");
+    }
+
+    URL parsedUrl = new URL(urlString);
+
+    // Validate scheme
+    if (!ALLOWED_SCHEMES.contains(parsedUrl.getProtocol().toLowerCase())) {
+      throw new SpRuntimeException("Only HTTP and HTTPS protocols are allowed");
+    }
+
+    // Validate host against allowlist
+    String host = parsedUrl.getHost().toLowerCase();
+    if (!ALLOWED_HOSTS.contains(host)) {
+      throw new SpRuntimeException("Host is not in the allowed list: " + host);
+    }
+
+    // Additional SSRF protection - check for private IP addresses
+    InetAddress[] addresses = InetAddress.getAllByName(host);
+    for (InetAddress addr : addresses) {
+      if (addr.isAnyLocalAddress() || addr.isLoopbackAddress() || addr.isLinkLocalAddress() ||
+          addr.isSiteLocalAddress() || addr.isMulticastAddress()) {
+        throw new SpRuntimeException("Access to private/internal addresses is not allowed");
+      }
+    }
+  }
+}

