+const crypto = require('crypto');
+
+// Generate a random CSRF token
+function generateToken() {
+  return crypto.randomBytes(32).toString('hex');
+}
+
+// Create CSRF middleware
+function csrfMiddleware() {
+  return function(req, res, next) {
+    // Skip CSRF check for non-state-changing requests
+    if (['GET', 'HEAD', 'OPTIONS'].includes(req.method)) {
+      return next();
+    }
+
+    // Generate token for GET requests to include in forms
+    if (req.method === 'GET') {
+      req.csrfToken = generateToken();
+      res.locals.csrfToken = req.csrfToken;
+      return next();
+    }
+
+    // Validate CSRF token for state-changing requests
+    const token = req.headers['x-csrf-token'] || 
+                  req.body._csrf || 
+                  req.query._csrf;
+
+    if (!token || token !== req.session.csrfToken) {
+      return res.status(403).json({
+        error: 'CSRF token validation failed'
+      });
+    }
+
+    next();
+  };
+}
+
+// Initialize session with CSRF token
+function initCsrfSession(req, res, next) {
+  if (!req.session) {
+    req.session = {};
+  }
+  if (!req.session.csrfToken) {
+    req.session.csrfToken = generateToken();
+  }
+  next();
+}
+
+module.exports = { csrfMiddleware, initCsrfSession, generateToken };
