diff --git a/packages/nodes-base/nodes/Python/PythonCodeValidator.ts b/packages/nodes-base/nodes/Python/PythonCodeValidator.ts
new file mode 100644
index 0000000..1234567
--- /dev/null
+++ b/packages/nodes-base/nodes/Python/PythonCodeValidator.ts
@@ -0,0 +1,85 @@
+import { NodeOperationError } from 'n8n-workflow';
+
+/**
+ * Security validation for Python code to prevent sandbox escape
+ */
+export interface ValidationResponse {
+	valid: boolean;
+	error?: string;
+}
+
+/**
+ * Dangerous Python imports and functions that could escape sandbox
+ */
+const DANGEROUS_PATTERNS = [
+	'import os',
+	'import sys',
+	'import subprocess',
+	'import socket',
+	'import pickle',
+	'import marshal',
+	'import __import__',
+	'__import__',
+	'exec(',
+	'eval(',
+	'compile(',
+	'open(',
+	'__import__',
+	'__builtins__',
+	'globals()',
+	'locals()',
+	'__class__',
+	'__mro__',
+	'__subclasses__',
+	'__globals__',
+	'__code__',
+	'__func__',
+	'__self__',
+	'__dict__',
+	'__reduce__',
+	'__reduce_ex__',
+	'__getattribute__',
+	'__setattr__',
+	'__delattr__',
+	'__getstate__',
+	'__setstate__',
+	'__getnewargs__',
+	'__getnewargs_ex__',
+	'__getinitargs__',
+	'__getstate__',
+	'__setstate__',
+	'__reduce__',
+	'__reduce_ex__',
+	'__getattribute__',
+	'__setattr__',
+	'__delattr__',
+	'__getstate__',
+	'__setstate__',
+	'__getnewargs__',
+	'__getnewargs_ex__',
+	'__getinitargs__',
+	'__getstate__',
+	'__setstate__',
+	'__reduce__',
+	'__reduce_ex__',
+	'__getattribute__',
+	'__setattr__',
+	'__delattr__',
+	'__getstate__',
+	'__setstate__',
+	'__getnewargs__',
+	'__getnewargs_ex__',
+	'__getinitargs__',
+];
+
+/**
+ * Validate Python code for security issues
+ */
+export function validatePythonCode(code: string): ValidationResponse {
+	const normalizedCode = code.toLowerCase();
+
+	for (const pattern of DANGEROUS_PATTERNS) {
+		if (normalizedCode.includes(pattern.toLowerCase())) {
+			return {
+				valid: false,
+				error: `Potentially dangerous Python operation detected: ${pattern}. This could allow sandbox escape.`,
+			};
+		}
+	}
+
+	// Additional check for code injection patterns
+	if (normalizedCode.includes('importlib') || normalizedCode.includes('pkgutil')) {
+		return {
+			valid: false,
+			error: 'Dynamic module loading is not allowed in the Python sandbox.',
+		};
+	}
+
