 'use strict';

 const parseLinkHeader = (header) => {
+  if (typeof header !== 'string' || header.length > 10000) {
+    throw new Error('Invalid header: input too long');
+  }
+
   const links = [];
   const regex = /<([^>]+)>(?:;([^;]+))?/g;
   let match;

   while ((match = regex.exec(header)) !== null) {
     const url = match[1];
     const params = match[2] || '';
     const link = { url };

     if (params) {
       const paramRegex = /([^=]+)=([^;]+)/g;
       let paramMatch;
       while ((paramMatch = paramRegex.exec(params)) !== null) {
         link[paramMatch[1]] = paramMatch[2];
       }
     }

     links.push(link);
   }

   return links;
 };

 module.exports = parseLinkHeader;

