+ * @returns {boolean} - True if the value is safe to spread
+ */
+export function isDynamicImportExpression(value) {
+  // Check if value is a Promise (dynamic import returns a Promise)
+  if (value instanceof Promise) {
+    // Additional check to identify dynamic import specifically
+    // This is a simplified check - in production would need more robust detection
+    const promisePrototype = Object.getPrototypeOf(value);
+    if (promisePrototype && promisePrototype.constructor.name === 'Promise') {
+      // Check for dynamic import markers
+      // In practice, this would need to track the origin of the promise
+      return true;
+    }
+  }
+  return false;
+}
+
+/**
+ * Validates spread operator usage to prevent dynamic import exploitation
+ * @param {*} spreadValue - The value being spread
+ * @returns {boolean} - True if spread is safe
+ */
+export function validateSpreadValue(spreadValue) {
+  return !isDynamicImportExpression(spreadValue);
+}
